pub fn quicksort(arr: &mut [i32]) {
    if arr.len() <= 16 {
        insertion_sort(arr);
        return;
    }
    let pivot_idx = partition(arr);
    quicksort(&mut arr[..pivot_idx]);
    quicksort(&mut arr[pivot_idx + 1..]);
}

fn insertion_sort(arr: &mut [i32]) {
    for i in 1..arr.len() {
        let key = arr[i];
        let mut j = i;
        while j > 0 && arr[j - 1] > key {
            arr[j] = arr[j - 1];
            j -= 1;
        }
        arr[j] = key;
    }
}

fn median_of_three(arr: &mut [i32]) -> usize {
    let mid = arr.len() / 2;
    let last = arr.len() - 1;
    if arr[0] > arr[mid] { arr.swap(0, mid); }
    if arr[0] > arr[last] { arr.swap(0, last); }
    if arr[mid] > arr[last] { arr.swap(mid, last); }
    arr.swap(mid, last - 1); // put pivot at last-1
    last - 1
}

fn partition(arr: &mut [i32]) -> usize {
    let pivot_pos = median_of_three(arr);
    let pivot = arr[pivot_pos];
    arr.swap(pivot_pos, 0);
    let mut i = 1;
    let mut j = arr.len() - 1;

    loop {
        while i <= j && arr[i] <= pivot { i += 1; }
        while j > 0 && arr[j] > pivot { j -= 1; }
        if i >= j { break; }
        arr.swap(i, j);
    }
    arr.swap(0, j);
    j
}
